type workspaceThenLoader[Q orm.Loadable] struct {
	Accounts     func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	Categories   func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	Members      func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	Transactions func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
}

func buildWorkspaceThenLoader[Q orm.Loadable]() workspaceThenLoader[Q] {
	type AccountsLoadInterface interface {
		LoadAccounts(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type CategoriesLoadInterface interface {
		LoadCategories(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type MembersLoadInterface interface {
		LoadMembers(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type TransactionsLoadInterface interface {
		LoadTransactions(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}

	return workspaceThenLoader[Q]{
		Accounts: thenLoadBuilder[Q](
			"Accounts",
			func(ctx context.Context, exec bob.Executor, retrieved AccountsLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadAccounts(ctx, exec, mods...)
			},
		),
		Categories: thenLoadBuilder[Q](
			"Categories",
			func(ctx context.Context, exec bob.Executor, retrieved CategoriesLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCategories(ctx, exec, mods...)
			},
		),
		Members: thenLoadBuilder[Q](
			"Members",
			func(ctx context.Context, exec bob.Executor, retrieved MembersLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadMembers(ctx, exec, mods...)
			},
		),
		Transactions: thenLoadBuilder[Q](
			"Transactions",
			func(ctx context.Context, exec bob.Executor, retrieved TransactionsLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadTransactions(ctx, exec, mods...)
			},
		),
	}
}

// LoadAccounts loads the workspace's Accounts into the .R struct
func (o *Workspace) LoadAccounts(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Accounts = nil

	related, err := o.Accounts(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, rel := range related {
		rel.R.Workspace = o
	}

	o.R.Accounts = related
	return nil
}

// LoadAccounts loads the workspace's Accounts into the .R struct
func (os WorkspaceSlice) LoadAccounts(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	accounts, err := os.Accounts(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.Accounts = nil
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range accounts {

			if !(o.ID == rel.WorkspaceID) {
				continue
			}

			rel.R.Workspace = o

			o.R.Accounts = append(o.R.Accounts, rel)
		}
	}

	return nil
}

