type workspaceJoins[Q dialect.Joinable] struct {
	typ          string
	Accounts     modAs[Q, accountColumns]
	Categories   modAs[Q, categoryColumns]
	Members      modAs[Q, memberColumns]
	Transactions modAs[Q, transactionColumns]
}

func (j workspaceJoins[Q]) aliasedAs(alias string) workspaceJoins[Q] {
	return buildWorkspaceJoins[Q](buildWorkspaceColumns(alias), j.typ)
}

func buildWorkspaceJoins[Q dialect.Joinable](cols workspaceColumns, typ string) workspaceJoins[Q] {
	return workspaceJoins[Q]{
		typ: typ,
		Accounts: modAs[Q, accountColumns]{
			c: Accounts.Columns,
			f: func(to accountColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Accounts.Name().As(to.Alias())).On(
						to.WorkspaceID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		Categories: modAs[Q, categoryColumns]{
			c: Categories.Columns,
			f: func(to categoryColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Categories.Name().As(to.Alias())).On(
						to.WorkspaceID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		Members: modAs[Q, memberColumns]{
			c: Members.Columns,
			f: func(to memberColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Members.Name().As(to.Alias())).On(
						to.WorkspaceID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		Transactions: modAs[Q, transactionColumns]{
			c: Transactions.Columns,
			f: func(to transactionColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Transactions.Name().As(to.Alias())).On(
						to.WorkspaceID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
